/// <summary>
/// The main method that initiates the report execution and routes the design.
/// </summary>
/// <param name="_args">The arguments passed from the menu item.</param>
public static void main(Args _args)
{
    ETGVendorOpenTransController controller = new ETGVendorOpenTransController();

    // Pass the caller arguments to the controller
    controller.parmArgs(_args);

    // Check the current legal entity (company)
    if (curExt() == 'e016')
    {
        // If legal entity is e016, use the specific e016 design
        controller.parmReportName(ssrsReportStr(ETGVendorOpenTrans, Design_E016));
    }
    else
    {
        // Otherwise, route to the default precision design
        controller.parmReportName(ssrsReportStr(ETGVendorOpenTrans, PrecisionDesign1));
    }

    // Execute the report
    controller.startOperation();
}
